import Link from "next/link";
import DisclaimerBanner from "../components/DisclaimerBanner";
import { getDictionary, getLocale } from "../lib/i18n";

const HomePage = async () => {
  const dict = getDictionary(await getLocale());

  return (
    <div className="section space-y-12">
      <section className="space-y-6">
        <span className="badge">{dict.homeBadge}</span>
        <h1 className="text-4xl font-semibold text-slate-900">
          {dict.homeTitle}
        </h1>
        <p className="max-w-2xl text-lg text-slate-600">
          {dict.homeSubtitle}
        </p>
        <div className="flex flex-wrap gap-4">
          <Link className="rounded-full bg-emerald-600 px-6 py-3 text-white" href="/chat">
            {dict.homeCtaPrimary}
          </Link>
          <Link className="rounded-full border border-slate-300 px-6 py-3 text-slate-700" href="/laws">
            {dict.homeCtaSecondary}
          </Link>
        </div>
      </section>

      <DisclaimerBanner text={dict.disclaimer} />

      <section className="grid gap-6 md:grid-cols-3">
        <div className="card">
          <h2 className="text-lg font-semibold">{dict.homeCard1Title}</h2>
          <p className="mt-2 text-slate-600">
            {dict.homeCard1Body}
          </p>
        </div>
        <div className="card">
          <h2 className="text-lg font-semibold">{dict.homeCard2Title}</h2>
          <p className="mt-2 text-slate-600">
            {dict.homeCard2Body}
          </p>
        </div>
        <div className="card">
          <h2 className="text-lg font-semibold">{dict.homeCard3Title}</h2>
          <p className="mt-2 text-slate-600">
            {dict.homeCard3Body}
          </p>
        </div>
      </section>
    </div>
  );
};

export default HomePage;
